import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int bufferSize = 10;

        // Limit user input to the size of the buffer
        char[] buffer = new char[bufferSize];
        int length = Math.min(userInput.length(), bufferSize);

        userInput.getChars(0, length, buffer, 0); // Copy only up to 'length' characters

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
